class Solution {
public:
    int findTheLongestSubstring(string s) {
        int n = s.size();
        int mask = 0, res = 0;
        unordered_map<int, int> seen;
        seen[0] = -1;
        for (int i = 0; i < n; ++i) {
            char c = s[i];
            if (c == 'a') mask ^= 1;
            else if (c == 'e') mask ^= 2;
            else if (c == 'i') mask ^= 4;
            else if (c == 'o') mask ^= 8;
            else if (c == 'u') mask ^= 16;
            if (seen.count(mask)) res = max(res, i - seen[mask]);
            else seen[mask] = i;
        }
        return res;
    }
};
efficiency: HIGH
time complexity: O(N)
space complexity: O(N)
energy implications: LOW
explanation: Utilizes bitmasking to track parity of vowel counts and a hashmap to store seen masks, enabling efficient lookup and update of the longest substring. 
